ALTER TABLE public.opportunities DROP CONSTRAINT IF EXISTS opportunities_funnel_stage_check; ALTER TABLE public.opportunities ADD CONSTRAINT opportunities_funnel_stage_check CHECK (funnel_stage IN ('prospeccao', 'contato', 'qualificacao', 'diagnostico', 'proposta', 'fechamento', 'icp_definido', 'segmentacao', 'contato_realizado', 'follow_up', 'proposta_enviada', 'negociacao', 'onboarding'));